import { useState, useEffect, useCallback, type ReactNode, type HTMLAttributes } from 'react'
import { Copy, Check } from 'lucide-react'
import { useHighlighter } from './useHighlighter'
import { useTheme } from '../../context/theme'
import { cn } from '@/lib/utils'

const COPY_FEEDBACK_MS = 1500

/* ===========================
   CodeBlock (root)
   =========================== */

export interface CodeBlockProps
  extends Omit<HTMLAttributes<HTMLDivElement>, 'className'> {
  /** Additional CSS class for external overrides */
  className?: string
  /** CodeBlockContent */
  children: ReactNode
}

export function CodeBlock({ className, children, ...rest }: CodeBlockProps) {
  return (
    <div
      className={cn(
        'group/code relative bg-muted border border-border rounded-md overflow-hidden',
        className
      )}
      {...rest}
    >
      {children}
    </div>
  )
}

/* ===========================
   CodeBlockContent
   =========================== */

export interface CodeBlockContentProps
  extends Omit<HTMLAttributes<HTMLPreElement>, 'className' | 'children'> {
  /** Language identifier — enables syntax highlighting */
  language?: string
  /** Show line numbers in the gutter */
  showLineNumbers?: boolean
  /** Additional CSS class for external overrides */
  className?: string
  /** Code string to display */
  children: string
}

export function CodeBlockContent({
  language,
  showLineNumbers = false,
  className,
  children,
  ...rest
}: CodeBlockContentProps) {
  const { resolvedTheme } = useTheme()
  const { tokens, ready } = useHighlighter(children, language, resolvedTheme)
  const [copied, setCopied] = useState(false)

  // Auto-reset copied state with proper cleanup on unmount
  useEffect(() => {
    if (!copied) return
    const timer = setTimeout(() => setCopied(false), COPY_FEEDBACK_MS)
    return () => clearTimeout(timer)
  }, [copied])

  const handleCopy = useCallback(() => {
    navigator.clipboard.writeText(children).then(() => setCopied(true))
  }, [children])

  const lines = children.split('\n')

  if (lines.length > 1 && lines[lines.length - 1] === '') {
    lines.pop()
  }

  const renderLine = (lineIndex: number) => {
    if (ready && tokens[lineIndex]) {
      return tokens[lineIndex].map((token, j) => (
        <span key={j} style={token.color ? { color: token.color } : undefined}>
          {token.content}
        </span>
      ))
    }
    return lines[lineIndex] || '\n'
  }

  return (
    <pre
      className={cn(
        'm-0 p-3 px-4 overflow-x-auto font-mono text-sm leading-relaxed text-foreground bg-transparent',
        'focus-visible:outline-2 focus-visible:outline-primary focus-visible:-outline-offset-2 focus-visible:rounded-sm',
        className
      )}
      tabIndex={0}
      role="region"
      aria-label={language ? `Code block, ${language}` : 'Code block'}
      {...rest}
    >
      <button
        className={cn(
          'absolute top-2 right-2 flex items-center justify-center w-7 h-7 p-0 bg-card border border-border rounded-sm text-secondary-foreground text-sm cursor-pointer opacity-0 group-hover/code:opacity-100 transition-all duration-100 ease-out hover:bg-background hover:text-foreground focus-visible:outline-2 focus-visible:outline-primary focus-visible:outline-offset-2 focus-visible:opacity-100 motion-reduce:transition-none',
          copied && 'text-composure-success'
        )}
        onClick={handleCopy}
        aria-label={copied ? 'Copied!' : 'Copy code'}
        aria-pressed={copied || undefined}
        title={copied ? 'Copied!' : 'Copy code'}
      >
        {copied ? <Check className="size-[1em]" /> : <Copy className="size-[1em]" />}
      </button>
      <code
        className={cn(
          'block whitespace-pre font-[inherit] text-[inherit] leading-[inherit] text-inherit',
          showLineNumbers && '[display:table] w-full'
        )}
        {...(language ? { 'data-language': language } : {})}
      >
        {showLineNumbers
          ? lines.map((_, i) => (
              <span key={i} className="code-line">
                <span className="code-line-number" aria-hidden="true">
                  {i + 1}
                </span>
                <span className="code-line-content">
                  {renderLine(i)}
                </span>
              </span>
            ))
          : ready && tokens.length > 0
            ? tokens.map((line, i) => (
                <span key={i}>
                  {line.map((token, j) => (
                    <span
                      key={j}
                      style={token.color ? { color: token.color } : undefined}
                    >
                      {token.content}
                    </span>
                  ))}
                  {i < tokens.length - 1 ? '\n' : ''}
                </span>
              ))
            : children}
      </code>
    </pre>
  )
}

import { useState, useEffect, useMemo } from 'react'
import { type HighlighterCore, type ThemedToken } from 'shiki/core'
import { createHighlighterCore } from 'shiki/core'
import { createJavaScriptRegexEngine } from 'shiki/engine/javascript'

/**
 * Shared highlighter singleton. Lazily initialized on first use.
 * Uses the JavaScript RegExp engine (no WASM) for smaller bundle size.
 */
let highlighterPromise: Promise<HighlighterCore> | null = null
let highlighterInstance: HighlighterCore | null = null

// Languages loaded so far (to avoid redundant imports)
const loadedLanguages = new Set<string>()

// Map of language IDs to their dynamic import functions
const languageImports: Record<string, () => Promise<unknown>> = {
  javascript: () => import('shiki/langs/javascript.mjs'),
  js: () => import('shiki/langs/javascript.mjs'),
  typescript: () => import('shiki/langs/typescript.mjs'),
  ts: () => import('shiki/langs/typescript.mjs'),
  tsx: () => import('shiki/langs/tsx.mjs'),
  jsx: () => import('shiki/langs/jsx.mjs'),
  python: () => import('shiki/langs/python.mjs'),
  py: () => import('shiki/langs/python.mjs'),
  css: () => import('shiki/langs/css.mjs'),
  html: () => import('shiki/langs/html.mjs'),
  json: () => import('shiki/langs/json.mjs'),
  bash: () => import('shiki/langs/bash.mjs'),
  sh: () => import('shiki/langs/bash.mjs'),
  shell: () => import('shiki/langs/shellscript.mjs'),
  rust: () => import('shiki/langs/rust.mjs'),
  go: () => import('shiki/langs/go.mjs'),
  java: () => import('shiki/langs/java.mjs'),
  ruby: () => import('shiki/langs/ruby.mjs'),
  sql: () => import('shiki/langs/sql.mjs'),
  yaml: () => import('shiki/langs/yaml.mjs'),
  yml: () => import('shiki/langs/yaml.mjs'),
  markdown: () => import('shiki/langs/markdown.mjs'),
  md: () => import('shiki/langs/markdown.mjs'),
  c: () => import('shiki/langs/c.mjs'),
  cpp: () => import('shiki/langs/cpp.mjs'),
}

// Canonical language name (resolve aliases)
const languageAliases: Record<string, string> = {
  js: 'javascript',
  ts: 'typescript',
  py: 'python',
  sh: 'bash',
  shell: 'shellscript',
  yml: 'yaml',
  md: 'markdown',
}

function getHighlighter(): Promise<HighlighterCore> {
  if (!highlighterPromise) {
    highlighterPromise = createHighlighterCore({
      themes: [
        import('shiki/themes/github-light.mjs'),
        import('shiki/themes/github-dark.mjs'),
      ],
      engine: createJavaScriptRegexEngine(),
    }).then((h) => {
      highlighterInstance = h
      return h
    })
  }
  return highlighterPromise
}

async function ensureLanguageLoaded(
  highlighter: HighlighterCore,
  language: string
): Promise<string | null> {
  const canonical = languageAliases[language] || language
  if (loadedLanguages.has(canonical)) return canonical

  const importFn = languageImports[language]
  if (!importFn) return null

  const lang = await importFn()
  await highlighter.loadLanguage(lang as Parameters<HighlighterCore['loadLanguage']>[0])
  loadedLanguages.add(canonical)
  return canonical
}

export interface HighlightResult {
  /** Tokenized lines — each line is an array of themed tokens */
  tokens: ThemedToken[][]
  /** Whether highlighting is ready (false during async load) */
  ready: boolean
}

/**
 * Synchronously highlight code if the highlighter and language are already
 * loaded. Returns null when the fast path isn't available (first load).
 */
function highlightSync(
  code: string,
  language: string,
  resolvedTheme?: 'light' | 'dark'
): ThemedToken[][] | null {
  if (!highlighterInstance) return null

  const canonical = languageAliases[language] || language
  if (!loadedLanguages.has(canonical)) return null

  const isDark =
    resolvedTheme != null
      ? resolvedTheme === 'dark'
      : window.matchMedia('(prefers-color-scheme: dark)').matches

  const { tokens } = highlighterInstance.codeToTokens(code, {
    lang: canonical,
    theme: isDark ? 'github-dark' : 'github-light',
  })

  return tokens
}

export function useHighlighter(
  code: string,
  language?: string,
  resolvedTheme?: 'light' | 'dark'
): HighlightResult {
  // Fast path: if highlighter + language are already loaded, compute
  // tokens synchronously. This eliminates the flash during streaming
  // where the component would render unhighlighted, then re-render
  // highlighted after the async effect completes.
  const syncTokens = useMemo(
    () => (language ? highlightSync(code, language, resolvedTheme) : null),
    [code, language, resolvedTheme]
  )

  const [asyncResult, setAsyncResult] = useState<HighlightResult>({
    tokens: [],
    ready: false,
  })

  useEffect(() => {
    // If sync path already produced tokens, skip the async work
    if (syncTokens || !language) {
      return
    }

    let cancelled = false

    async function highlight() {
      const highlighter = await getHighlighter()
      const canonicalLang = await ensureLanguageLoaded(highlighter, language!)
      if (cancelled || !canonicalLang) return

      const isDark =
        resolvedTheme != null
          ? resolvedTheme === 'dark'
          : window.matchMedia('(prefers-color-scheme: dark)').matches

      const { tokens } = highlighter.codeToTokens(code, {
        lang: canonicalLang,
        theme: isDark ? 'github-dark' : 'github-light',
      })

      if (!cancelled) {
        setAsyncResult({ tokens, ready: true })
      }
    }

    highlight()

    return () => {
      cancelled = true
    }
  }, [code, language, resolvedTheme, syncTokens])

  if (syncTokens) {
    return { tokens: syncTokens, ready: true }
  }

  return asyncResult
}
